import React from "react";
import styles from "./button-add.module.css";
import { useDispatch } from "react-redux";
import { addItem } from "../../app/cartSlice";

interface ButtonAddProps {
  product: {
    id: number;
    img: string;
    name: string;
    price: number;
  };
  quantity: number;
}

const ButtonAdd: React.FC<ButtonAddProps> = ({ product, quantity }) => {
  const dispatch = useDispatch();

  const cartItem = {
    id: product.id,
    name: product.name,
    price: product.price,
    img: product.img,
    quantity: quantity || 1,
  };

  const handleAddToCart = () => {
    console.log("Adding item to cart:", cartItem);
    dispatch(addItem(cartItem));
  };

  return (
    <button className={styles.button_add} onClick={handleAddToCart}>
      <img
        src="/images/Cart-green.svg"
        alt="cart-logo"
        width={24}
        height={24}
        className={styles.cart_image}
      />
      <span className={styles.button_text}>+ Add to cart</span>
    </button>
  );
};

export default ButtonAdd;




